import{_ as t,c as a,o as i,a2 as o}from"./chunks/framework.CIiVzG-O.js";const u=JSON.parse('{"title":"Finder Sync Extension","description":"","frontmatter":{},"headers":[],"relativePath":"guide/finder-sync.md","filePath":"guide/finder-sync.md","lastUpdated":1776396452000}'),n={name:"guide/finder-sync.md"};function s(l,e,r,d,c,h){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="finder-sync-extension" tabindex="-1">Finder Sync Extension <a class="header-anchor" href="#finder-sync-extension" aria-label="Permalink to &quot;Finder Sync Extension&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Nicasa Finder Sync Extension adds a toolbar button to macOS Finder, allowing you to quickly process image files without opening the main Nicasa app.</p><h3 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ul><li><strong>Image Optimizer</strong>: Compress and optimize selected images</li><li><strong>AI Image Editor</strong>: Edit selected images with AI (repair, enhance, fill, etc.)</li><li><strong>Quick access via Finder toolbar</strong></li><li><strong>Works with multiple selected images</strong></li></ul><h2 id="installation-setup" tabindex="-1">Installation &amp; Setup <a class="header-anchor" href="#installation-setup" aria-label="Permalink to &quot;Installation &amp; Setup&quot;">​</a></h2><h3 id="installing-via-nicasa-app" tabindex="-1">Installing via Nicasa App <a class="header-anchor" href="#installing-via-nicasa-app" aria-label="Permalink to &quot;Installing via Nicasa App&quot;">​</a></h3><p>The Finder Sync Extension is included with the main Nicasa app. After installing the app, enable the extension:</p><ol><li>Open <strong>System Settings</strong> &gt; <strong>Extensions</strong> &gt; <strong>Finder Extensions</strong></li><li>Toggle <strong>Nicasa Finder Sync</strong> on</li></ol><h3 id="toolbar-button" tabindex="-1">Toolbar Button <a class="header-anchor" href="#toolbar-button" aria-label="Permalink to &quot;Toolbar Button&quot;">​</a></h3><p>Once enabled, a Nicasa icon appears in the Finder toolbar.</p><p>If not visible:</p><ol><li>Right-click the Finder toolbar</li><li>Select <strong>Customize Toolbar...</strong></li><li>Drag the Nicasa button into place</li></ol><h2 id="using-the-finder-toolbar-button" tabindex="-1">Using the Finder Toolbar Button <a class="header-anchor" href="#using-the-finder-toolbar-button" aria-label="Permalink to &quot;Using the Finder Toolbar Button&quot;">​</a></h2><h3 id="selecting-files" tabindex="-1">Selecting Files <a class="header-anchor" href="#selecting-files" aria-label="Permalink to &quot;Selecting Files&quot;">​</a></h3><p>Open Finder and select one or more images. Supported formats:</p><ul><li><code>.jpg</code>, <code>.jpeg</code>, <code>.png</code>, <code>.gif</code>, <code>.bmp</code>, <code>.webp</code>, <code>.svg</code>, <code>.tiff</code>, <code>.ico</code></li></ul><h3 id="using-the-menu" tabindex="-1">Using the Menu <a class="header-anchor" href="#using-the-menu" aria-label="Permalink to &quot;Using the Menu&quot;">​</a></h3><p>Click the Nicasa toolbar button, then choose:</p><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><strong>Image Optimizer</strong></td><td>Compresses and optimizes the selected images</td></tr><tr><td><strong>AI Image Editor</strong></td><td>Opens the selected images in Nicasa&#39;s AI editor for repair, enhancement, or inpainting</td></tr></tbody></table><blockquote><p>⚠️ <strong>Note</strong>: If no file is selected, the button will beep and the action will not run.</p></blockquote><h3 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><ol><li>Select images in Finder</li><li>Click the Nicasa toolbar button → choose the desired action</li><li>The Nicasa app will open automatically and process the selected images</li></ol><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>For best results, select images inside a folder you have access to</li><li>You can select multiple files at once</li><li>If an image does not open, check that it is one of the supported formats</li><li>The extension works seamlessly with macOS sandboxing – you only need to authorize access the first time</li></ul>',25)])])}const g=t(n,[["render",s]]);export{u as __pageData,g as default};
